function load$&Identity;Grid$(g) {if (g._rowCount > 0) g._focusWhenTabChanged();}
/* <flatten type="Javascript"> */
function onChange$Lot$ReceiptDate(o) {
  var g = o.grid, r = g._activeRow, d = g._getItemValue(r, g._getColumnOrder('ngay_nhap'));
  if (!d) return;
  g._setItemValue(r, g._getColumnOrder('ngay_hhbh'), new Date(d.getTime() + (g._getItemValue(r, g._getColumnOrder('so_ngay_bh')) * 86400000)));
  g._setItemValue(r, g._getColumnOrder('ngay_hhsd'), g._getItemValue(r, g._getColumnOrder('kieu_lo')) == 1 ? new Date(d.getTime() + (g._getItemValue(r, g._getColumnOrder('so_ngay_sp')) * 86400000)) : null);
}
